import React from 'react';
import './SubmitLotus.css';

const C = '#8B1538';
const PETAL = 'M 0 0 C -9 -13 -10 -30 0 -48 C 10 -30 9 -13 0 0';
const ANGLES = [0, 45, 90, 135, 180, 225, 270, 315];

export default function SubmitLotus() {
  return (
    <svg
      className="submit-lotus"
      viewBox="0 0 200 200"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden="true"
    >
      {ANGLES.map(a => (
        <path
          key={a}
          d={PETAL}
          fill="none"
          stroke={C}
          strokeWidth="0.9"
          opacity="0.45"
          transform={`translate(100,100) rotate(${a})`}
        />
      ))}
      <circle cx="100" cy="100" r="4" fill="none" stroke={C} strokeWidth="0.9" opacity="0.45" />
    </svg>
  );
}
